data.code:
const responseData = JSON.parse(data.text);
  const campaign = responseData.emailCampaign;
  const metrics = campaign.metrics || {};
  const goals = campaign.goals || {};
  const ecommerce = campaign.ecommerce || {};

  // Extract goal data
  const goal1 = goals.goal1 || {};
  const goal2 = goals.goal2 || {};

  // Create row for Google Sheets with comprehensive data
  return {
    values: [[
      campaign.name,
      campaign.startDate,
      campaign.endDate,
      campaign.campaignID,
      campaign.utmSource,
      campaign.utmMedium,
      campaign.utmCampaign,
      campaign.utmContent,
      campaign.utmTerm,
      metrics.sessions,
      metrics.pageViews,
      metrics.uniquePageViews,
      metrics.averageSessionDuration,
      metrics.bounceRate,
      metrics.conversionRate,
      goal1.name || '',
      goal1.completions || 0,
      goal1.conversionRate || '0%',
      goal2.name || '',
      goal2.completions || 0,
      goal2.conversionRate || '0%',
      ecommerce.revenue,
      ecommerce.transactions,
      ecommerce.averageOrderValue
    ]]
  };

